import{c as t,Q as i,j as a,m as o}from"./chunks/framework.BPKcPtvA.js";const n="/videos/video-invite-acceptance.webm",g=JSON.parse('{"title":"Accepting an Invite","description":"","frontmatter":{},"headers":[],"relativePath":"guide/account/accepting-an-invite.md","filePath":"guide/account/accepting-an-invite.md","lastUpdated":1779094756000}'),r={name:"guide/account/accepting-an-invite.md"};function s(l,e,d,h,c,p){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="accepting-an-invite" tabindex="-1">Accepting an Invite <a class="header-anchor" href="#accepting-an-invite" aria-label="Permalink to &quot;Accepting an Invite&quot;">​</a></h1><p>You cannot self-register for the Console. Every account is created by an existing admin and arrives as an email invite. This page walks through what happens when you click that invite link.</p><video controls preload="metadata"><source src="'+n+'" type="video/webm"></video><h2 id="step-1-—-verify-the-invite" tabindex="-1">Step 1 — Verify the invite <a class="header-anchor" href="#step-1-—-verify-the-invite" aria-label="Permalink to &quot;Step 1 — Verify the invite&quot;">​</a></h2><p>Click the link in the invitation email. You land on the <strong>Accept Invite</strong> page, which has two steps. The first is verification.</p><ul><li>If the link includes the verification code (the common case), this step is skipped automatically and you go straight to Step 2.</li><li>If only the page URL was sent, paste the <strong>invite code</strong> from the email into the field and click <strong>Verify</strong>.</li></ul><p>If verification fails (wrong code, expired invite), you will see a &quot;Verification failed&quot; message. Ask the admin who invited you to resend.</p><h2 id="step-2-—-complete-your-profile" tabindex="-1">Step 2 — Complete your profile <a class="header-anchor" href="#step-2-—-complete-your-profile" aria-label="Permalink to &quot;Step 2 — Complete your profile&quot;">​</a></h2><p>After verification you are taken to the profile step. The form has:</p><ul><li>A <strong>password</strong> field and a <strong>confirm password</strong> field. As you type, a live checklist shows which rules are currently met (length, uppercase, lowercase, numbers, symbols). The exact rules depend on your organisation&#39;s password policy.</li><li>Your <strong>email</strong> and <strong>display name</strong>, shown read-only — they were set when you were invited.</li><li>Any <strong>custom profile fields</strong> your organisation has configured. These vary per customer. Required fields are marked with a red asterisk.</li><li>A <strong>Terms and Conditions</strong> checkbox that you must tick.</li></ul><p>Click <strong>Complete Setup</strong> when the form is valid.</p><h2 id="what-happens-after" tabindex="-1">What happens after <a class="header-anchor" href="#what-happens-after" aria-label="Permalink to &quot;What happens after&quot;">​</a></h2><ul><li>If your invite came from a regular sign-up flow, you land on your home page in the Console.</li><li>If your invite came from a partner application, you are redirected back to that application — you are now signed in there as well.</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td><strong>The link does nothing.</strong></td><td>The code may have expired. Ask the admin to resend.</td></tr><tr><td><strong>&quot;Passwords do not match&quot;</strong></td><td>Re-type the password in both fields exactly.</td></tr><tr><td><strong>The password checklist has unticked items even though my password looks complex.</strong></td><td>Read the rule names carefully — your organisation may require a symbol or a minimum length you have not met.</td></tr><tr><td><strong>A required field is rejected.</strong></td><td>Make sure required fields (marked with a red asterisk) are all filled.</td></tr><tr><td><strong>&quot;You must accept the Terms and Conditions.&quot;</strong></td><td>Tick the checkbox at the bottom of the form.</td></tr></tbody></table><p>After acceptance, future sign-ins use the standard sign-in flow — see <a href="./signing-in">Signing In</a>.</p>',16)])])}const m=t(r,[["render",s]]);export{g as __pageData,m as default};
